&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:400px;&quot; width=&quot;453&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td colspan=&quot;3&quot; style=&quot;width: 453px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;उच्चारणस्थान&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 60px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;स्थान&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 138px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सूत्र&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 256px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;व्याख्या&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 60px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;strong&gt;कण्ठ्य&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 138px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;strong&gt;अकुहविसर्जनीयानां कण्ठः&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 256px;&quot;&gt;
			&lt;p&gt;अ, आ, क वर्ग (क्, ख्, ग्, घ्, ङ्) ह् और विसर्ग का उच्चारणस्थान कण्ठ्य होता है।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;तालव्य&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;इचुयशानां तालुः&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 256px;&quot;&gt;
			&lt;p&gt;इ, ई, च वर्ग (च्, छ्, ज्, झ्, ञ्)&amp;nbsp;य्&amp;nbsp;और&amp;nbsp;श्&amp;nbsp;का उच्चारणस्थान तालव्य होता है।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 60px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;मूर्द्धन्य&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 138px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;ऋटुरषाणां मूर्द्धा&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 256px;&quot;&gt;
			&lt;p&gt;ऋ, ट वर्ग (ट्, ठ्,&amp;nbsp;ड्, ढ्, ण्) र् और ष् का उच्चारणस्थान मूर्धा होता है।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 60px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;दन्त्य&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 138px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;लृतुलसानां दन्ताः&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 256px;&quot;&gt;
			&lt;p&gt;लृ, त वर्ग (त्, थ्, द्, ध्, न्) ल् और स् का उच्चारणस्थान दन्त्य होता है।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 60px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;ओष्ठ्य&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 138px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;उपूपध्मानीयानां ओष्ठौ&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 256px;&quot;&gt;
			&lt;p&gt;उ, ऊ, प वर्ग (प्, फ्, ब्, भ्, म्) उपधमानीय ( ऍ, ऑ) का उच्चारणस्थान ओष्ठ्य है।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;नासिक्य&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;ञमङणनानां नासिका च&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 256px;&quot;&gt;
			&lt;p&gt;ञ्, म्, ङ्, ण्, न् और अनुनासिक का उच्चारणस्थान नासिका होता है।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;इसके अतिरिक्त अरबी फारसी में प्रयुक्त &amp;#39;क़, ख़, ग़&amp;zwnj;&amp;#39; वर्णों को&amp;nbsp;&lt;span style=&quot;border: 0px; margin: 0px; padding: 0px; font-weight: 700;&quot;&gt;जिह्वामूलीय&amp;nbsp;&lt;/span&gt;कहा जाता है।&lt;span style=&quot;border: 0px; margin: 0px; padding: 0px; font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;दो स्थानों को मिलाकर भी कुछ वर्णों के उच्चारण स्थान होते हैं-&lt;/p&gt;

