			&lt;td style=&quot;width: 321px; height: 19px;&quot;&gt;
			&lt;p&gt;ए और ऐ का उच्चारणस्थान कण्ठतालु होता है।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 94px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;दन्तोष्ठं&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 198px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;वकारस्य दन्तोष्ठं&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 321px;&quot;&gt;
			&lt;p&gt;व का उच्चारणस्थान दन्तोष्ठ होता है।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 94px; text-align: center;&quot;&gt;कण्ठोष्ठं&lt;/td&gt;
			&lt;td style=&quot;width: 198px;&quot;&gt;ओ&lt;span style=&quot;text-align: -webkit-center;&quot;&gt;दौ&lt;/span&gt;तो कण्ठोष्ठ्म्&lt;/td&gt;
			&lt;td style=&quot;width: 321px;&quot;&gt;ओ&amp;nbsp;तथा&amp;nbsp;औ&amp;nbsp;का उच्चारणस्थान&amp;nbsp;&lt;span style=&quot;text-align: center;&quot;&gt;कण्ठो&lt;/span&gt;&lt;span style=&quot;text-align: -webkit-center;&quot;&gt;ष्ठ&lt;/span&gt;&amp;nbsp;होता है।&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
