&lt;p&gt;नल और दमयन्ती की प्रणयकथा&amp;nbsp;का वर्णन&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;नैषधीयचरित्&amp;#39; &lt;/span&gt;महाकाव्य में हुआ है, जो&amp;nbsp;श्रीहर्ष की रचना है -&amp;nbsp;​&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;background-color:rgb(255, 255, 255);width:250px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
